<?php
namespace App\Domain\Combat\Data;use InvalidArgumentException;
final class CombatMitigationConfig{private $defense,$absorb,$total,$minimum;public function __construct($defense,$absorb,$total,$minimum){foreach([$defense,$absorb,$total,$minimum]as$v)if(!is_int($v))throw new InvalidArgumentException('Combat mitigation configuration must use integers.');if($defense<1||$defense>9500||$absorb<0||$absorb>9500||$total<1||$total>9900||$minimum<1)throw new InvalidArgumentException('Invalid combat mitigation configuration.');$this->defense=$defense;$this->absorb=$absorb;$this->total=$total;$this->minimum=$minimum;}public static function defaults(){return new self(7000,7000,9000,1);}public function defenseReductionCapBasisPoints(){return$this->defense;}public function absorbDamageCapBasisPoints(){return$this->absorb;}public function totalMitigationCapBasisPoints(){return$this->total;}public function minimumDamage(){return$this->minimum;}public function toArray(){return['defense_reduction_cap_basis_points'=>$this->defense,'absorb_damage_cap_basis_points'=>$this->absorb,'total_mitigation_cap_basis_points'=>$this->total,'minimum_damage'=>$this->minimum];}public static function fromArray(array $v){return new self((int)$v['defense_reduction_cap_basis_points'],(int)$v['absorb_damage_cap_basis_points'],(int)$v['total_mitigation_cap_basis_points'],(int)$v['minimum_damage']);}}
